#include <vector>
#include <algorithm>

struct DSU {
    std::vector<int> parent;
    std::vector<int> rank;
    int count;

    DSU(int n) : parent(n), rank(n, 0), count(n) {
        for (int i = 0; i < n; ++i) {
            parent[i] = i;
        }
    }

    int find(int x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    bool union(int x, int y) {
        int rootX = find(x);
        int rootY = find(y);
        if (rootX == rootY) return false;
        if (rank[rootX] < rank[rootY]) {
            parent[rootX] = rootY;
        } else {
            parent[rootY] = rootX;
            if (rank[rootX] == rank[rootY]) {
                rank[rootX]++;
            }
        }
        count--;
        return true;
    }
};

long long solve(long long n, std::vector<std::vector<long long>> edges, long long k) {
    if (edges.empty()) {
        return 0;
    }
    std::sort(edges.begin(), edges.end(), [](const std::vector<long long>& a, const std::vector<long long>& b) {
        return a[2] < b[2];
    });
    long long low = 0;
    long long high = edges.back()[2];
    long long answer = high;

    while (low <= high) {
        long long mid = (low + high) / 2;
        DSU dsu(n);
        for (const auto& edge : edges) {
            if (edge[2] <= mid) {
                dsu.union(edge[0], edge[1]);
            }
        }
        if (dsu.count <= k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return answer;
}
```

