```typescript
function solve(n: number, edges: number[][], k: number): number {
    // Sort edges by weight
    edges.sort((a, b) => a[2] - b[2]);
    const maxWeight = edges[edges.length - 1][2];

    // Binary search between low and high
    let low = 0, high = maxWeight;
    let answer = maxWeight;

    // DSU helper class
    class DSU {
        parent: number[];
        rank: number[];
        count: number;

        constructor(size: number) {
            this.parent = Array(size).fill(0).map((_, i) => i);
            this.rank = Array(size).fill(0);
            this.count = size;
        }

        find(x: number): number {
            if (this.parent[x] !== x) {
                this.parent[x] = this.find(this.parent[x]);
            }
            return this.parent[x];
        }

        union(x: number, y: number): boolean {
            const rootX = this.find(x);
            const rootY = this.find(y);
            if (rootX === rootY) return false;
            if (this.rank[rootX] < this.rank[rootY]) {
                this.parent[rootX] = rootY;
            } else {
                this.parent[rootY] = rootX;
                if (this.rank[rootX] === this.rank[rootY]) {
                    this.rank[rootX]++;
                }
            }
            this.count--;
            return true;
        }
    }

    function isPossible(X: number): boolean {
        const dsu = new DSU(n);
        for (const [u, v, w] of edges) {
            if (w <= X) {
                dsu.union(u, v);
            }
        }
        return dsu.count <= k;
    }

    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        if (isPossible(mid)) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return answer;
}
```

