#include <vector>
#include <algorithm>
#include <functional>

long long solve(long long n, std::vector<std::vector<long long>> edges, long long k) {
    if (edges.empty()) {
        return 0;
    }
    std::sort(edges.begin(), edges.end(), [](const std::vector<long long>& a, const std::vector<long long>& b) {
        return a[2] < b[2];
    });
    long long maxWeight = edges.back()[2];

    long long low = 0, high = maxWeight;
    long long answer = maxWeight;

    struct DSU {
        std::vector<long long> parent;
        std::vector<long long> rank;
        long long count;

        DSU(long long size) : parent(size), rank(size, 0), count(size) {
            for (long long i = 0; i < size; ++i) {
                parent[i] = i;
            }
        }

        long long find(long long x) {
            if (parent[x] != x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        }

        bool union_(long long x, long long y) {
            long long rootX = find(x);
            long long rootY = find(y);
            if (rootX == rootY) return false;
            if (rank[rootX] < rank[rootY]) {
                parent[rootX] = rootY;
            } else {
                parent[rootY] = rootX;
                if (rank[rootX] == rank[rootY]) {
                    rank[rootX]++;
                }
            }
            count--;
            return true;
        }
    };

    auto isPossible = [&](long long X) -> bool {
        DSU dsu(n);
        for (const auto& edge : edges) {
            if (edge[2] <= X) {
                dsu.union_(edge[0], edge[1]);
            }
        }
        return dsu.count <= k;
    };

    while (low <= high) {
        long long mid = (low + high) / 2;
        if (isPossible(mid)) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return answer;
}
