                this.parent[rootX] = rootY;
            } else {
                this.parent[rootY] = rootX;
                if (this.rank[rootX] === this.rank[rootY]) {
                    this.rank[rootX]++;
                }
            }
            this.count--;
            return true;
        }
    }

    function isPossible(X: number): boolean {
        const dsu = new DSU(n);
        for (const [u, v, w] of edges) {
            if (w <= X) {
                dsu.union(u, v);
            }
        }
        return dsu.count <= k;
    }

    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        if (isPossible(mid)) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return answer;
}
